const item = $input.first();
const body = item.json.body || item.json;
const email = (body.email || '').toString().trim().toLowerCase();
const subject = (body.subject || '').toString().trim();
const description = (body.description || '').toString().trim();
const missing = [];
if (!email || !email.includes('@')) missing.push('email');
if (!subject || subject.length < 3) missing.push('subject');
if (!description || description.length < 10) missing.push('description');
if (missing.length > 0) {
  return [{ json: { valid: false, error: 'Missing: ' + missing.join(', '), missingFields: missing, receivedAt: new Date().toISOString() } }];
}
const ticketId = 'TKT-' + Date.now() + '-' + Math.random().toString(36).substr(2,5).toUpperCase();
return [{ json: { valid: true, ticketId: ticketId, email: email, subject: subject, description: description, receivedAt: new Date().toISOString() } }];

