const agentOut = $input.first().json;
const c = agentOut.output || agentOut;
const src = $('Validate Input').first().json;
const ticketData = {
  ticketId: src.ticketId,
  email: src.email,
  subject: src.subject,
  description: src.description,
  receivedAt: src.receivedAt,
  team: c.team || 'tech_support',
  priority: c.priority || 'medium',
  category: c.category || 'general',
  summary: c.summary || src.subject,
  confidence: parseFloat(c.confidence) || 0.5,
  status: 'open'
};
return [{ json: ticketData }];

const t = $('Prepare Ticket Data').first().json;
const pMap = { high: '[HIGH]', medium: '[MED]', low: '[LOW]' };
const tMap = { tech_support: 'Tech Support', billing: 'Billing', sales: 'Sales', rma: 'RMA' };
const notif = {
  type: 'new_ticket',
  ticket_id: t.ticketId,
  team: t.team,
  priority: t.priority,
  message: (pMap[t.priority] || '[?]') + ' ' + (tMap[t.team] || t.team) + ' - ' + t.email + ': ' + t.subject + ' (' + t.category + ')',
  created_at: new Date().toISOString()
};
return [{ json: notif }];
